<template>
  <view class="pill">
    <view class="bar"><view class="fill" :style="{width: percent + '%'}"/></view>
    <text class="label">{{value}}/{{max}}</text>
  </view>
</template>

<script>
export default {
  name: 'ProgressPill',
  props: {
    value: { type: Number, default: 0 },
    max: { type: Number, default: 1 }
  },
  computed: {
    percent: function(){
      var v = this.value || 0;
      var m = this.max || 1;
      return Math.min(100, Math.round((v/m)*100 || 0));
    }
  }
}
</script>

<style scoped>
.pill{ display:flex; align-items:center; gap:8px; }
.bar{ width:80px; height:8px; background:#eee; border-radius:8px; overflow:hidden; }
.fill{ height:100%; background:#2E8B57; }
.label{ font-size:12px; color:#6B7280; }
</style>